const { app } = require('@azure/functions');
const { CosmosClient } = require('@azure/cosmos');

// Secure configuration with environment variables
const cosmosEndpoint = process.env.COSMOS_ENDPOINT;
const cosmosKey = process.env.COSMOS_KEY;
const databaseId = process.env.COSMOS_DATABASE_ID;
const containerId = process.env.COSMOS_CONTAINER_ID;

// Input validation constants
const MAX_BATCH_SIZE = 1000;
const MIN_BATCH_SIZE = 1;
const ALLOWED_OPERATIONS = ['transform', 'aggregate', 'export'];

// Initialize Cosmos Client with secure connection
const cosmosClient = new CosmosClient({
    endpoint: cosmosEndpoint,
    key: cosmosKey,
    connectionPolicy: {
        requestTimeout: 540000 // 9 minutes
    }
});

const database = cosmosClient.database(databaseId);
const container = database.container(containerId);

// Secure input validation
function validateInput(input) {
    const errors = [];

    if (!input || typeof input !== 'object') {
        errors.push('Invalid input: must be an object');
        return { valid: false, errors };
    }

    // Validate operation type
    if (!input.operation || !ALLOWED_OPERATIONS.includes(input.operation)) {
        errors.push(`Invalid operation: must be one of ${ALLOWED_OPERATIONS.join(', ')}`);
    }

    // Validate batch size
    const batchSize = parseInt(input.batchSize, 10);
    if (isNaN(batchSize) || batchSize < MIN_BATCH_SIZE || batchSize > MAX_BATCH_SIZE) {
        errors.push(`Invalid batchSize: must be between ${MIN_BATCH_SIZE} and ${MAX_BATCH_SIZE}`);
    }

    // Validate filter if provided
    if (input.filter) {
        if (typeof input.filter !== 'object') {
            errors.push('Invalid filter: must be an object');
        }
        // Prevent SQL injection by validating filter keys
        const allowedFilterKeys = ['status', 'category', 'dateRange', 'id'];
        const filterKeys = Object.keys(input.filter);
        const invalidKeys = filterKeys.filter(key => !allowedFilterKeys.includes(key));
        if (invalidKeys.length > 0) {
            errors.push(`Invalid filter keys: ${invalidKeys.join(', ')}`);
        }
    }

    // Validate continuation token if provided
    if (input.continuationToken && typeof input.continuationToken !== 'string') {
        errors.push('Invalid continuationToken: must be a string');
    }

    return {
        valid: errors.length === 0,
        errors
    };
}

// Secure query builder with parameterized queries
function buildSecureQuery(filter) {
    let query = 'SELECT * FROM c WHERE 1=1';
    const parameters = [];

    if (filter) {
        if (filter.status) {
            query += ' AND c.status = @status';
            parameters.push({ name: '@status', value: filter.status });
        }

        if (filter.category) {
            query += ' AND c.category = @category';
            parameters.push({ name: '@category', value: filter.category });
        }

        if (filter.id) {
            query += ' AND c.id = @id';
            parameters.push({ name: '@id', value: filter.id });
        }

        if (filter.dateRange && filter.dateRange.start && filter.dateRange.end) {
            query += ' AND c.timestamp >= @startDate AND c.timestamp <= @endDate';
            parameters.push(
                { name: '@startDate', value: filter.dateRange.start },
                { name: '@endDate', value: filter.dateRange.end }
            );
        }
    }

    return { query, parameters };
}

// Secure data processing functions
function transformData(items) {
    return items.map(item => {
        // Remove sensitive fields from processing
        const { _rid, _self, _etag, _attachments, _ts, ...safeData } = item;
        
        return {
            id: safeData.id,
            processedAt: new Date().toISOString(),
            data: safeData,
            status: 'processed'
        };
    });
}

function aggregateData(items) {
    const aggregation = {
        totalCount: items.length,
        categories: {},
        statusCounts: {}
    };

    items.forEach(item => {
        if (item.category) {
            aggregation.categories[item.category] = (aggregation.categories[item.category] || 0) + 1;
        }
        if (item.status) {
            aggregation.statusCounts[item.status] = (aggregation.statusCounts[item.status] || 0) + 1;
        }
    });

    return aggregation;
}

function exportData(items) {
    return items.map(item => {
        const { _rid, _self, _etag, _attachments, _ts, ...exportData } = item;
        return exportData;
    });
}

// Main batch processing function
async function processBatch(context, input) {
    const startTime = Date.now();
    const results = {
        processedCount: 0,
        totalItems: 0,
        continuationToken: null,
        operation: input.operation,
        errors: []
    };

    try {
        const { query, parameters } = buildSecureQuery(input.filter);
        
        const querySpec = {
            query,
            parameters
        };

        const queryOptions = {
            maxItemCount: input.batchSize,
            continuationToken: input.continuationToken || undefined
        };

        const queryIterator = container.items.query(querySpec, queryOptions);
        
        let hasMoreResults = true;
        let processedData = [];

        while (hasMoreResults) {
            const elapsedTime = Date.now() - startTime;
            
            // Safety check: leave 30 seconds buffer before timeout
            if (elapsedTime > 570000) {
                context.log('Approaching timeout, saving progress');
                results.continuationToken = queryIterator.continuationToken;
                break;
            }

            const response = await queryIterator.fetchNext();
            
            if (!response.resources || response.resources.length === 0) {
                hasMoreResults = false;
                break;
            }

            const items = response.resources;
            results.totalItems += items.length;

            // Process based on operation type
            let processed;
            switch (input.operation) {
                case 'transform':
                    processed = transformData(items);
                    break;
                case 'aggregate':
                    processed = aggregateData(items);
                    break;
                case 'export':
                    processed = exportData(items);
                    break;
                default:
                    throw new Error('Invalid operation');
            }

            processedData.push(processed);
            results.processedCount += items.length;

            // Store continuation token for resumption
            if (queryIterator.hasMoreResults) {
                results.continuationToken = response.continuationToken;
            } else {
                hasMoreResults = false;
            }

            context.log(`Processed ${results.processedCount} items`);
        }

        results.data = input.operation === 'aggregate' 
            ? processedData.reduce((acc, curr) => {
                acc.totalCount += curr.totalCount;
                Object.assign(acc.categories, curr.categories);
                Object.assign(acc.statusCounts, curr.statusCounts);
                return acc;
            }, { totalCount: 0, categories: {}, statusCounts: {} })
            : processedData.flat();

    } catch (error) {
        context.log.error('Processing error:', error.message);
        results.errors.push({
            message: 'Processing error occurred',
            timestamp: new Date().toISOString()
        });
        throw error;
    }

    return results;
}

